import{_ as o,C as n,o as l,c as s,E as i,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Moving to Slovenia","description":"Immigration pathways and relocation guide for Slovenia","frontmatter":{"layout":"doc","title":"Moving to Slovenia","description":"Immigration pathways and relocation guide for Slovenia"},"headers":[],"relativePath":"europe/slovenia/moving-there.md","filePath":"europe/slovenia/moving-there.md","lastUpdated":null}'),h={name:"europe/slovenia/moving-there.md"};function u(g,e,m,c,f,b){const t=n("Badge");return l(),s("div",null,[i(t,{variant:"green"},{default:a(()=>[...e[0]||(e[0]=[r("EU: Free Movement",-1)])]),_:1}),i(t,{variant:"yellow"},{default:a(()=>[...e[1]||(e[1]=[r("Non-EU: Work Permit",-1)])]),_:1}),i(t,{variant:"yellow"},{default:a(()=>[...e[2]||(e[2]=[r("No Specific DN Visa",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="moving-to-slovenia" tabindex="-1">Moving to Slovenia <a class="header-anchor" href="#moving-to-slovenia" aria-label="Permalink to &quot;Moving to Slovenia&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eea-eu-citizens" tabindex="-1">EEA/EU Citizens <a class="header-anchor" href="#eea-eu-citizens" aria-label="Permalink to &quot;EEA/EU Citizens&quot;">​</a></h3><ul><li><strong>Free movement rights</strong> — no visa required</li><li><strong>Up to 3 months</strong>: No formalities</li><li><strong>Over 3 months</strong>: Register with the Administrative Unit (Upravna enota) and obtain a residence certificate</li><li><strong>Right to work</strong>: Automatic</li><li><strong>EMŠO (Personal ID number)</strong>: Required for all official services</li></ul><h3 id="uk-citizens-post-brexit" tabindex="-1">UK Citizens (Post-Brexit) <a class="header-anchor" href="#uk-citizens-post-brexit" aria-label="Permalink to &quot;UK Citizens (Post-Brexit)&quot;">​</a></h3><ul><li><strong>Schengen Area</strong>: Visa-free for up to 90 days in any 180-day period</li><li><strong>Longer stays</strong>: Apply for residence permit: <ul><li>Work permit (job offer from Slovenian employer)</li><li>Student visa (enrollment at Slovenian university)</li><li>Family reunification</li><li>Temporary residence for business purposes</li></ul></li></ul><h3 id="third-country-nationals" tabindex="-1">Third-Country Nationals <a class="header-anchor" href="#third-country-nationals" aria-label="Permalink to &quot;Third-Country Nationals&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>Work Permit</td><td>Job offer from Slovenian employer</td><td>Up to 1 year, renewable</td></tr><tr><td>EU Blue Card</td><td>Highly skilled (salary ~€35,000+/year)</td><td>Up to 4 years</td></tr><tr><td>Student Visa</td><td>Enrollment at accredited institution</td><td>Duration of studies</td></tr><tr><td>Family Reunification</td><td>Family ties to Slovenian resident</td><td>Tied to sponsor&#39;s status</td></tr><tr><td>Business Visa</td><td>Self-employment or business activity</td><td>Up to 1 year, renewable</td></tr><tr><td>Temporary Residence</td><td>Various grounds (study, work, family)</td><td>1 year, renewable</td></tr></tbody></table><h2 id="digital-nomad-remote-work" tabindex="-1">Digital Nomad / Remote Work <a class="header-anchor" href="#digital-nomad-remote-work" aria-label="Permalink to &quot;Digital Nomad / Remote Work&quot;">​</a></h2><p>Slovenia does <strong>not have a dedicated digital nomad visa</strong>. Remote workers can consider:</p><ul><li><strong>Temporary residence permit for business</strong>: For self-employed individuals with a registered business</li><li><strong>Work permit</strong>: If employed by a Slovenian company</li><li><strong>Tourist visa</strong>: Up to 90 days (no work permitted)</li><li>Some remote workers use the <strong>EU Blue Card</strong> route if employed by a tech company</li></ul><h2 id="moving-checklist" tabindex="-1">Moving Checklist <a class="header-anchor" href="#moving-checklist" aria-label="Permalink to &quot;Moving Checklist&quot;">​</a></h2><h3 id="before-moving" tabindex="-1">Before Moving <a class="header-anchor" href="#before-moving" aria-label="Permalink to &quot;Before Moving&quot;">​</a></h3><ul><li>[ ] <strong>Passport</strong>: Valid for duration of stay</li><li>[ ] <strong>Visa</strong>: Apply 2-3 months in advance</li><li>[ ] <strong>Healthcare</strong>: Private health insurance initially; register with ZZZS after residency</li><li>[ ] <strong>HRT</strong>: Get 3-6 month supply and doctor&#39;s letter (translated to Slovenian)</li><li>[ ] <strong>Banking</strong>: Consider NLB, Nova KBM, or Revolut</li><li>[ ] <strong>Housing</strong>: Research rental market (nepremicnine.si, bolha.com)</li><li>[ ] <strong>Language</strong>: Slovenian essential for bureaucracy; English in Ljubljana</li><li>[ ] <strong>Document translation</strong>: Official Slovenian translations needed</li></ul><h3 id="after-arrival" tabindex="-1">After Arrival <a class="header-anchor" href="#after-arrival" aria-label="Permalink to &quot;After Arrival&quot;">​</a></h3><ul><li>[ ] Register residence with Administrative Unit (Upravna enota)</li><li>[ ] Obtain EMŠO (personal identification number)</li><li>[ ] Register with ZZZS (Health Insurance Institute)</li><li>[ ] Open local bank account</li><li>[ ] Get local SIM card (Telekom Slovenije, A1, Telemach)</li><li>[ ] Connect with LGBTQ+ community (Legebitra, TransAkcija)</li><li>[ ] Register with University Medical Centre Ljubljana for trans healthcare</li></ul><h2 id="practical-information" tabindex="-1">Practical Information <a class="header-anchor" href="#practical-information" aria-label="Permalink to &quot;Practical Information&quot;">​</a></h2><h3 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h3><ul><li><strong>Moderate</strong> — comparable to southern EU</li><li>Monthly rent (1-bed): €500-900 (Ljubljana), €350-600 (Maribor), €300-500 (other cities)</li><li>Monthly groceries: €250-400</li><li>Public transport: €30-50/month (Ljubljana)</li><li>Dining out: €10-20 per meal</li></ul><h3 id="best-cities-for-lgbtq-community" tabindex="-1">Best Cities for LGBTQ+ Community <a class="header-anchor" href="#best-cities-for-lgbtq-community" aria-label="Permalink to &quot;Best Cities for LGBTQ+ Community&quot;">​</a></h3><table tabindex="0"><thead><tr><th>City</th><th>LGBTQ+ Scene</th><th>Trans Healthcare</th></tr></thead><tbody><tr><td><strong>Ljubljana</strong></td><td>Good (Pride, bars, community)</td><td>Best (UKCL)</td></tr><tr><td><strong>Maribor</strong></td><td>Moderate</td><td>Limited</td></tr><tr><td><strong>Koper</strong></td><td>Limited</td><td>None</td></tr></tbody></table><h3 id="climate" tabindex="-1">Climate <a class="header-anchor" href="#climate" aria-label="Permalink to &quot;Climate&quot;">​</a></h3><ul><li><strong>Continental</strong>: Cold winters (-5°C to 5°C), warm summers (20-30°C)</li><li><strong>Coastal (Primorska)</strong>: Mediterranean influence, milder winters</li><li><strong>Alpine</strong>: Colder, snow in winter</li><li><strong>Best time to arrive</strong>: Spring or early autumn</li></ul><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><ul><li>Official language: Slovenian (South Slavic language)</li><li>English: Widely spoken in Ljubljana, especially among under 40s</li><li>Other languages: Croatian, Serbian, and Bosnian widely understood</li><li>Free Slovenian language courses available for immigrants</li><li>Slovenian is essential for official documents and healthcare</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.gov.si/en/state-authorities/ministries/ministry-of-the-interior/" target="_blank" rel="noreferrer">Ministry of the Interior (Immigration)</a></li><li><a href="https://www.zzzs.si/" target="_blank" rel="noreferrer">ZZZS (Health Insurance Institute)</a></li><li><a href="https://www.gov.si/en/topics/relocation-to-slovenia/" target="_blank" rel="noreferrer">Government of Slovenia - Relocation</a></li><li><a href="https://www.legebitra.si/" target="_blank" rel="noreferrer">Legebitra (LGBTQ+ Organization)</a></li><li><a href="https://transakcija.si/" target="_blank" rel="noreferrer">TransAkcija</a></li><li><a href="https://www.nepremicnine.si/" target="_blank" rel="noreferrer">Nepremičnine (housing)</a></li></ul>',27))])}const y=o(h,[["render",u]]);export{v as __pageData,y as default};
